import React from 'react';

function LandingPage({ onNavigate }) {
    return (
        <div style={{
            minHeight: '100vh',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '32px',
            position: 'relative',
            overflow: 'hidden'
        }}>
            {/* Animated background circles */}
            <div style={{
                position: 'absolute',
                top: '10%',
                left: '10%',
                width: '300px',
                height: '300px',
                borderRadius: '50%',
                background: 'radial-gradient(circle, rgba(102, 126, 234, 0.15) 0%, transparent 70%)',
                animation: 'pulse 8s ease-in-out infinite',
                zIndex: 0
            }}></div>
            <div style={{
                position: 'absolute',
                bottom: '15%',
                right: '15%',
                width: '400px',
                height: '400px',
                borderRadius: '50%',
                background: 'radial-gradient(circle, rgba(0, 242, 254, 0.12) 0%, transparent 70%)',
                animation: 'pulse 10s ease-in-out infinite',
                animationDelay: '2s',
                zIndex: 0
            }}></div>

            {/* Content */}
            <div style={{
                maxWidth: '900px',
                textAlign: 'center',
                zIndex: 1,
                animation: 'fadeIn 1s ease-out'
            }}>
                {/* Badge */}
                <div style={{
                    display: 'inline-block',
                    padding: '10px 24px',
                    background: 'rgba(255, 255, 255, 0.05)',
                    backdropFilter: 'blur(20px)',
                    borderRadius: '50px',
                    border: '1px solid rgba(255, 255, 255, 0.1)',
                    marginBottom: '32px',
                    fontSize: '0.9rem',
                    color: '#00f2fe',
                    fontWeight: 600,
                    letterSpacing: '1px',
                    animation: 'slideInLeft 0.8s ease-out'
                }}>
                    🌱 SUSTAINABLE AI MONITORING
                </div>

                {/* Main Title */}
                <h1 style={{
                    fontSize: 'clamp(3rem, 8vw, 5.5rem)',
                    fontWeight: 900,
                    margin: '0 0 24px 0',
                    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 50%, #f093fb 100%)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    backgroundClip: 'text',
                    letterSpacing: '-0.03em',
                    lineHeight: 1.1,
                    animation: 'fadeIn 1.2s ease-out'
                }}>
                    Green AI Monitor
                </h1>

                {/* Subtitle */}
                <p style={{
                    fontSize: 'clamp(1.1rem, 2.5vw, 1.5rem)',
                    color: '#a0a0b8',
                    maxWidth: '700px',
                    margin: '0 auto 48px',
                    lineHeight: 1.6,
                    animation: 'fadeIn 1.4s ease-out'
                }}>
                    Track, analyze, and optimize your AI model's carbon footprint in real-time with powerful insights and actionable recommendations
                </p>

                {/* Features Grid */}
                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                    gap: '24px',
                    marginBottom: '48px',
                    animation: 'fadeIn 1.6s ease-out'
                }}>
                    {[
                        { icon: '⚡', title: 'Real-Time', desc: 'Live monitoring' },
                        { icon: '📊', title: 'Analytics', desc: 'Deep insights' },
                        { icon: '🌍', title: 'Eco-Friendly', desc: 'Carbon tracking' },
                        { icon: '💡', title: 'Smart Tips', desc: 'Optimization' }
                    ].map((feature, index) => (
                        <div
                            key={index}
                            className="glass-card"
                            style={{
                                padding: '24px',
                                textAlign: 'center',
                                transition: 'all 0.3s ease',
                                animationDelay: `${1.6 + index * 0.1}s`,
                                animation: 'fadeIn 0.6s ease-out backwards'
                            }}
                        >
                            <div style={{ fontSize: '2.5rem', marginBottom: '12px' }}>{feature.icon}</div>
                            <div style={{ fontSize: '1.1rem', fontWeight: 700, color: '#ffffff', marginBottom: '4px' }}>
                                {feature.title}
                            </div>
                            <div style={{ fontSize: '0.85rem', color: '#6b6b7e' }}>{feature.desc}</div>
                        </div>
                    ))}
                </div>

                {/* CTA Button */}
                <button
                    onClick={onNavigate}
                    style={{
                        padding: '18px 48px',
                        fontSize: '1.1rem',
                        fontWeight: 700,
                        color: '#ffffff',
                        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                        border: 'none',
                        borderRadius: '50px',
                        cursor: 'pointer',
                        transition: 'all 0.3s ease',
                        boxShadow: '0 8px 32px rgba(102, 126, 234, 0.4)',
                        animation: 'fadeIn 1.8s ease-out, pulse 2s ease-in-out infinite 2s',
                        position: 'relative',
                        overflow: 'hidden'
                    }}
                    onMouseEnter={(e) => {
                        e.target.style.transform = 'translateY(-2px) scale(1.05)';
                        e.target.style.boxShadow = '0 12px 48px rgba(102, 126, 234, 0.6)';
                    }}
                    onMouseLeave={(e) => {
                        e.target.style.transform = 'translateY(0) scale(1)';
                        e.target.style.boxShadow = '0 8px 32px rgba(102, 126, 234, 0.4)';
                    }}
                >
                    🚀 Start Monitoring
                </button>

                {/* Stats */}
                <div style={{
                    display: 'flex',
                    justifyContent: 'center',
                    gap: '48px',
                    marginTop: '64px',
                    flexWrap: 'wrap',
                    animation: 'fadeIn 2s ease-out'
                }}>
                    {[
                        { value: 'Real-Time', label: 'Monitoring' },
                        { value: 'AI-Powered', label: 'Insights' },
                        { value: 'Carbon', label: 'Tracking' }
                    ].map((stat, index) => (
                        <div key={index} style={{ textAlign: 'center' }}>
                            <div style={{
                                fontSize: '1.8rem',
                                fontWeight: 800,
                                color: '#4facfe',
                                marginBottom: '4px'
                            }}>
                                {stat.value}
                            </div>
                            <div style={{ fontSize: '0.9rem', color: '#6b6b7e' }}>{stat.label}</div>
                        </div>
                    ))}
                </div>
            </div>

            {/* Footer */}
            <div style={{
                position: 'absolute',
                bottom: '24px',
                color: '#6b6b7e',
                fontSize: '0.85rem',
                zIndex: 1
            }}>
                Built with 💚 for a sustainable AI future
            </div>
        </div>
    );
}

export default LandingPage;
